window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]=window.__LIBQ["pham-nhan-tu-tien"]["q06"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]["artifacts"]={"updatedAt":"2026-07-15","count":55,"artifacts":[{"id":"truy-ma-lenh","name":"Trụy Ma Lệnh","cn":"墜魔令","aliases":["Trụy Ma Lệnh bài"],"category":"khac","categoryLabel":"Lệnh bài","phamCap":"Chưa rõ","soHuu":["Nho sinh cẩm bào"],"trangThai":"dang-co","blurb":"Lệnh bài bằng thanh đồng do Quỷ Linh Môn phát hành, cho phép đi qua khe hở không gian ở cốc khẩu Trụy Ma Cốc. Giá ba vạn linh thạch mỗi cái.","detail":"Mặt trước khắc hai chữ đỏ \"Trụy Ma\", mặt sau chữ \"Lệnh\" vàng tản linh khí. Quỷ Linh Môn phát hành cho các tông phái và tán tu, tổng hơn một trăm cái cho tông phái nhỏ và tán tu, ngoài ra còn phát cho các tông phái lớn. Là vật bắt buộc để qua khe hở không gian nguy hiểm ở cốc khẩu Trụy Ma Cốc.","phanLoaiPhu":"Lệnh bài nhập cốc","hinhDang":"Lệnh bài thanh đồng, mặt trước hai chữ đỏ, mặt sau một chữ vàng tản linh khí","vatLieu":"Thanh đồng","nguonGoc":"Do Quỷ Linh Môn chế tạo và phát hành dựa trên phương pháp nhập Trụy Ma Cốc họ phát hiện","congNang":["Cho phép đi qua khe hở không gian ở cốc khẩu Trụy Ma Cốc"],"chuSoHuu":[{"ten":"Nho sinh cẩm bào","tuChuong":"@c0793","denChuong":"","cachCoDuoc":"Mua từ Quỷ Linh Môn với giá ba vạn linh thạch mỗi cái","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0793","loai":"xuat-hien","importance":"normal","giaiDoan":"Quỷ Linh Môn phát hành lệnh bài cho tu sĩ nhập Trụy Ma Cốc","text":"Quỷ Linh Môn phát hành Trụy Ma Lệnh bài cho các tông phái và tán tu, thu ba vạn linh thạch mỗi cái. Nho sinh cẩm bào mua ba cái với giá mười vạn linh thạch.","anchor":"một cái lệnh bài làm bằng thanh đồng. mặt trên có hai chữ màu đỏ \" Trụy Ma.\""}]},"capNhatToi":"@c0793","nguon":["@c0793"]},{"id":"dong-phuc-thien-ky","name":"Động phúc thiên kỳ","aliases":["Ống trúc vàng"],"category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Ống trúc màu vàng dài khoảng một trượng mà Hàn Lập mang sau lưng khi trở về từ cực tây, không thu vào túi trữ vật được.","detail":"Hàn Lập mang theo sau lưng khi xuất hiện tại thành Diệp Hoa. Vật phẩm có kích thước lớn, dài khoảng một trượng, màu vàng, không thể thu vào túi trữ vật. Bên trong chứa gì chưa được tiết lộ.","hinhDang":"Ống trúc màu vàng, dài khoảng một trượng","nguonGoc":"Hàn Lập mang về từ chuyến đi cực tây","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0794","denChuong":"","cachCoDuoc":"Mang về từ chuyến đi cực tây","trangThai":"dang-co"}],"congNang":["Chưa rõ — không thu vào túi trữ vật được"],"tabs":{"tienTrinh":[{"chuong":"@c0794","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Hàn Lập mang ống trúc vàng dài khoảng một trượng sau lưng khi trở về Thiên Nam, không thu vào túi trữ vật.","anchor":"Phía sau sau lưng hắn còn có một cái ống trúc màu vàng thật to dài khoảng một trượng"}]},"capNhatToi":"@c0794","nguon":["@c0794"]},{"id":"linh-chuc-qua","name":"Linh Chúc Quả","category":"khac","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":[],"trangThai":"chua-thu-thap","blurb":"Linh dược quý hiếm nằm sâu trong Trụy Ma Cốc, là mục tiêu chính của nhóm Hàn Lập và Quỷ Linh Môn khi nhập cốc.","detail":"Nằm ở vùng sâu nhất trong Trụy Ma Cốc, nơi nguy hiểm gấp bội. Cả nhóm Hàn Lập lẫn Quỷ Linh Môn đều muốn lấy được. Tử Linh cho rằng cần ra tay trước Quỷ Linh Môn.","congNang":["Chưa rõ tác dụng cụ thể, có giá trị cực lớn với tu sĩ","Nguyên liệu chính luyện chế Tạo Hóa Đan @c0795"],"tabs":{"tienTrinh":[{"chuong":"@c0794","loai":"nhắc tới","importance":"normal","giaiDoan":"Được đề cập là mục tiêu nhập cốc","text":"Tử Linh cho rằng cần ra tay trước Quỷ Linh Môn để lấy Linh Chúc Quả nằm sâu trong Trụy Ma Cốc.","anchor":"Chỉ có như vậy, chúng ta mới có thể ra tay trước Quỷ Linh Môn mà lấy đi Linh Chúc Quả"},{"chuong":"@c0795","loai":"xuat-hien","importance":"major","giaiDoan":"Xác nhận tồn tại","text":"Tử Linh đưa ngọc giản của trưởng lão Quỷ Linh Môn cho Hàn Lập xem, xác nhận Linh Chúc Quả tồn tại sâu trong Trụy Ma Cốc.","anchor":"Chuyện Linh Chúc quả đúng là có thật. Chuyện này là do một trưởng lão của Quỷ Linh Môn năm đó còn sống trở ra cho biết"}]},"capNhatToi":"@c0794","nguon":["@c0794","@c0795"]},{"id":"tao-hoa-dan","name":"Tạo Hóa Đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":[],"trangThai":"chua-luyen-che","blurb":"Đan dược luyện từ Linh Chúc Quả cùng phụ liệu, phải luyện và dùng ngay trong Trụy Ma Cốc. Là mục tiêu chính của Hàn Lập và Tử Linh khi vào cốc.","detail":"Tạo Hóa Đan cần nguyên liệu chính là Linh Chúc Quả và các phụ liệu khác. Tử Linh đã chuẩn bị hơn mười mấy phần phụ liệu. Phải luyện chế và sử dụng ngay trong Trụy Ma Cốc vì Linh Chúc Quả giảm hiệu lực nếu mang ra ngoài. Công dụng cụ thể chưa được tiết lộ.","congNang":["Công dụng cụ thể chưa lộ, là mục tiêu chính của Hàn Lập và Tử Linh @c0795"],"tabs":{"tienTrinh":[{"chuong":"@c0795","loai":"xuat-hien","importance":"major","giaiDoan":"Thảo luận kế hoạch luyện chế","text":"Hàn Lập và Tử Linh thống nhất luyện chế Tạo Hóa Đan ngay trong Trụy Ma Cốc, Tử Linh đã chuẩn bị hơn mười mấy phần phụ liệu.","anchor":"Phụ trợ tài liệu cho Tạo hóa đan này cũng không khó tìm. Trong mấy năm thời gian này ta cũng đã chuẩn bị được mười mấy phần"}]},"capNhatToi":"@c0795","nguon":["@c0795"]},{"id":"ngoc-gian-bich-luc","name":"Ngọc giản bích lục","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Tử Linh Tiên Tử"],"trangThai":"dang-co","blurb":"Ngọc giản do trưởng lão Nguyên Anh Quỷ Linh Môn năm xưa để lại, miêu tả chi tiết vị trí Linh Chúc Quả trong Trụy Ma Cốc.","detail":"Ngọc giản ghi lại vị trí Linh Chúc Quả do trưởng lão Quỷ Linh Môn tìm thấy khi xuất khiếu Nguyên Anh trong Trụy Ma Cốc. Tử Linh đưa cho Hàn Lập xem, hắn nhận xét vị trí hơi mập mờ nhưng không phủ nhận.","congNang":["Bản đồ chỉ dẫn tìm Linh Chúc Quả trong Trụy Ma Cốc @c0795"],"tabs":{"tienTrinh":[{"chuong":"@c0795","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập xem ngọc giản","text":"Tử Linh đưa ngọc giản cho Hàn Lập xem, hắn đem thần thức đắm chìm vào trong đó.","anchor":"ta đây còn có một cái ngọc giản chính là do vị nguyên anh lão giả năm đó miêu tả chi tiết vị trí của Linh Chúc Quả"}]},"capNhatToi":"@c0795","nguon":["@c0795"]},{"id":"hat-chau-dan-hon-moc","name":"Hạt châu dẫn hồn mộc","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Đại Diễn Thần Quân"],"trangThai":"dang-co","blurb":"Vật phẩm do Hàn Lập chế, được Đại Diễn Thần Quân sử dụng để duy trì tinh hồn nhưng chỉ kéo dài thêm hơn mười năm.","detail":"Do Hàn Lập chế tạo, Đại Diễn Thần Quân dùng để duy trì tinh hồn. Tuy nhiên chỉ có thể kéo dài thêm hơn mười năm, sau đó tinh hồn sẽ tan.","nguon":["@c0795"]},{"id":"duong-hon-moc","name":"Dưỡng Hồn Mộc","cn":"养魂木","category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"Chí bảo","soHuu":["Hàn Lập"],"trangThai":"Cho mượn","blurb":"Chí bảo có khả năng tư dưỡng nguyên thần, Hàn Lập cho Đại Diễn Thần Quân mượn dùng để đổi lấy ba tầng sau Đại Diễn Quyết và Khôi Lỗi Thuật.","detail":"Chí bảo quý hiếm có công năng tư dưỡng nguyên thần, hỗ trợ Đại Diễn Thần Quân duy trì tồn tại (không có thì lão chỉ sống thêm khoảng một năm rưỡi). Hàn Lập cho lão mượn dùng trong cuộc giao dịch lớn, đổi lấy ba tầng sau Đại Diễn Quyết và Khôi Lỗi Thuật.","congNang":["Tư dưỡng nguyên thần, hỗ trợ duy trì thần hồn tồn tại"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0796","denChuong":"","cachCoDuoc":"Sở hữu từ trước","trangThai":"Cho Đại Diễn Thần Quân mượn"},{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0796","denChuong":"","cachCoDuoc":"Hàn Lập cho mượn","trangThai":"Đang mượn dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0796","loai":"đổi chủ","importance":"major","giaiDoan":"Hàn Lập cho Đại Diễn Thần Quân mượn","text":"Hàn Lập cho Đại Diễn Thần Quân mượn Dưỡng Hồn Mộc để đổi lấy ba tầng sau Đại Diễn Quyết và Khôi Lỗi Thuật.","anchor":"Ngươi cư nhiên còn có Dưỡng Hồn Mộc chí bảo. Có khả năng hỗ trợ ta"}]},"nguon":["@c0796"]},{"id":"lenh-bai-thien-cuc-mon","name":"Lệnh bài Thiên Cực Môn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lệnh bài màu vàng, mặt khắc nổi ba chữ Thiên Cực Môn. Hàn Lập lấy ra xem xét cuối chương với ánh mắt đầy tính toán.","detail":"Lệnh bài màu vàng, mặt khắc nổi ba chữ Thiên Cực Môn. Hàn Lập lấy ra ngồi xuống xem xét, mắt nheo lại phát tinh quang lập lòe trong bóng đêm, thái độ suy tư. Chưa rõ công dụng cụ thể và nguồn gốc cách Hàn Lập có được.","hinhDang":"Lệnh bài màu vàng, khắc nổi ba chữ Thiên Cực Môn","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0797","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0797","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện lần đầu","text":"Hàn Lập lấy ra lệnh bài vàng khắc ba chữ Thiên Cực Môn, mắt nheo phát tinh quang suy tư.","anchor":"Nhìn trên mặt lệnh bài này có khắc nổi ba chữ \" Thiên Cực Môn \""}]},"nguon":["@c0797"]},{"id":"luong-nghi-hoan","name":"Lưỡng nghi hoàn","cn":"兩儀環","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Pháp bảo trong tay Hàn Lập, có thể dùng làm vật dẫn khiến Nam Lũng Hầu chủ động tìm đến.","detail":"Hàn Lập tự tin rằng nhờ có Lưỡng nghi hoàn trong tay, Nam Lũng Hầu sẽ chủ động tìm đến mình mà không cần hắn đi tìm.","congNang":["Vật dẫn/liên lạc khiến Nam Lũng Hầu chủ động tìm đến","Miễn dịch/an toàn hoạt động trong vùng Bắc Cực Nguyên Quang @c0811"],"tabs":{"tienTrinh":[{"chuong":"@c0798","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập dùng làm lợi thế chờ Nam Lũng Hầu","text":"Hàn Lập tự tin rằng nhờ có Lưỡng nghi hoàn, Nam Lũng Hầu sẽ chủ động tìm đến cửa.","anchor":"Trong tay có Lưỡng nghi hoàn nên cho dù mình không đi tìm, phỏng chừng Nam Lũng Hầu cũng sẽ chủ động tìm đến cửa"},{"chuong":"@c0811","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng trước Bắc Cực Nguyên Quang","text":"Hàn Lập lấy ra nhẫn đen Lưỡng Nghi hoàn khi ba người gặp Bắc Cực Nguyên Quang chặn đường, là vật duy nhất an toàn sử dụng trong vùng hiểm trở này.","anchor":"một chiếc nhẫn đen thui bay ra, sau khi xoay quanh một cái thì rơi vào trong lòng bàn tay của hắn, linh quang trên bề mặt của nó chớp động không thôi"}]},"nguon":["@c0798","@c0811"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0811","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}]},{"id":"huyet-phuong-moc","name":"Huyết phượng mộc","cn":"血凤木","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Tài liệu luyện khí đỉnh bậc","soHuu":[],"trangThai":"chua-co","blurb":"Tài liệu luyện khí đỉnh bậc cực kỳ hiếm, là thành phần còn thiếu để Hàn Lập luyện chế Khôi Lỗi thượng cổ cấp Nguyên Anh.","detail":"Loại tài liệu luyện khí đỉnh bậc hiếm thấy, vô giá. Hàn Lập đã phân phó đệ tử Lạc Vân Tông lưu ý tìm kiếm nhưng trước khi vào Trụy Ma Cốc thì không thể có được.","congNang":["Thành phần thiết yếu để luyện chế Khôi Lỗi thượng cổ cấp Nguyên Anh"],"tabs":{"tienTrinh":[{"chuong":"@c0798","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc tới là tài liệu còn thiếu","text":"Hàn Lập xác nhận vẫn chưa thu thập được Huyết phượng mộc, đã phân phó đệ tử Lạc Vân Tông lưu ý tìm kiếm.","anchor":"Còn có một loại tài liệu gọi là “Huyết phượng mộc” vẫn chưa thu thập được"}]},"nguon":["@c0798"]},{"id":"kim-thu-ngan-but","name":"Kim Thư ngân bút","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo","soHuu":["Trần Xảo Thiên"],"trangThai":"dang-co","blurb":"Pháp bảo tổ truyền gia tộc Trần, Trần Xảo Thiên vừa luyện chế xong từ nguyên mẫu pháp khí phỏng chế. Có thể ngăn trở đại bộ phận độc phấn của độc nga.","detail":"Đệ tử Trần gia trước đó chỉ dùng bản pháp khí phỏng chế theo bộ pháp bảo gốc. Trần Xảo Thiên mất mấy năm tích cóp tài liệu, cuối cùng luyện chế xong pháp bảo thật, có thể ngăn trở đại bộ phận độc phấn của độc nga.","nguonGoc":"Tổ truyền gia tộc Trần, nâng cấp từ pháp khí phỏng chế","congNang":["Ngăn trở đại bộ phận độc phấn của độc nga"],"chuSoHuu":[{"ten":"Trần Xảo Thiên","tuChuong":"@c0799","denChuong":"","cachCoDuoc":"Tự luyện chế từ pháp khí tổ truyền","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0799","loai":"xuất hiện","importance":"normal","giaiDoan":"Trần Xảo Thiên luyện chế xong","text":"Trần Xảo Thiên tiết lộ vừa luyện chế xong Kim Thư ngân bút pháp bảo từ pháp khí tổ truyền Trần gia sau mấy năm tích cóp tài liệu.","anchor":"Trần gia đệ tử chúng ta sử dụng Kim Thư ngân bút pháp khí, kỳ thật chỉ là ứng chiếu theo bộ pháp bảo này mà phỏng chế thôi"}]},"nguon":["@c0799"]},{"id":"khoi-loi-hinh-cu-quy","name":"Khôi Lỗi hình cự quy","category":"phap-bao","categoryLabel":"Khôi Lỗi","phamCap":"Kết Đan Kỳ","soHuu":["Hàn Lập"],"trangThai":"dang-luyen-che","blurb":"Khôi Lỗi cấp Kết Đan hình cự quy, da dày chống năm ba đòn Nguyên Anh, phun lôi hỏa cầu uy lực ngang toàn lực Kết Đan Trung Kỳ, nhưng chậm chạp vụng về.","detail":"Da dày thịt béo, cho dù bị tu sĩ Nguyên Anh Kỳ công kích cũng chống đỡ được năm ba đòn. Miệng phun lôi hỏa cầu uy lực ngang toàn lực nhất kích tu sĩ Kết Đan Trung Kỳ. Nhược điểm: vụng về chậm chạp, dễ bị cận thân công kích.","hinhDang":"Hình cự quy (rùa lớn)","congNang":["Phòng ngự chống năm ba đòn Nguyên Anh Kỳ","Phun lôi hỏa cầu uy lực ngang toàn lực Kết Đan Trung Kỳ"],"uyLuc":"Phòng ngự chịu đòn Nguyên Anh, tấn công ngang Kết Đan Trung Kỳ","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0799","denChuong":"","cachCoDuoc":"Tự luyện chế theo phương pháp trong ngọc giản Đại diễn Thần Quân","trangThai":"dang-luyen-che"}],"tabs":{"tienTrinh":[{"chuong":"@c0799","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập bắt đầu luyện chế","text":"Hàn Lập nghiên cứu ngọc giản, nắm rõ đặc điểm Khôi Lỗi hình cự quy, quyết định luyện chế.","anchor":"da dày thịt béo, cho dù bị Nguyên Anh Kỳ tu sĩ công kích cũng có thể chống đỡ được năm ba đòn"}]},"nguon":["@c0799"]},{"id":"khoi-loi-hinh-ho-yeu","name":"Khôi Lỗi hình hổ yêu","category":"phap-bao","categoryLabel":"Khôi Lỗi","phamCap":"Kết Đan Kỳ","soHuu":["Hàn Lập"],"trangThai":"dang-luyen-che","blurb":"Khôi Lỗi cấp Kết Đan hình hổ yêu, không công kích tầm xa, phòng ngự trung bình, nhưng rất nhanh nhẹn, hổ trảo phóng trảo mang nửa thước xé rách vòng bảo hộ Kết Đan, chuyên cận chiến.","detail":"Không có khả năng công kích tầm xa, phòng ngự trung bình. Ưu thế: tốc độ cực nhanh, hổ trảo phóng ra trảo mang lớn đến nửa thước, trảo mang trong suốt có thể dễ dàng xé rách vòng bảo hộ tu sĩ Kết Đan bình thường. Chuyên cận chiến.","hinhDang":"Hình hổ yêu","congNang":["Cận chiến tốc độ cao","Hổ trảo phóng trảo mang nửa thước xé rách vòng bảo hộ Kết Đan"],"uyLuc":"Trảo mang xé vòng bảo hộ Kết Đan bình thường","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0799","denChuong":"","cachCoDuoc":"Tự luyện chế theo phương pháp trong ngọc giản Đại diễn Thần Quân","trangThai":"dang-luyen-che"}],"tabs":{"tienTrinh":[{"chuong":"@c0799","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập bắt đầu luyện chế","text":"Hàn Lập nghiên cứu ngọc giản, nắm rõ đặc điểm Khôi Lỗi hình hổ yêu, quyết định luyện chế.","anchor":"Một đôi hổ trảo có thể phóng ra trảo mang lớn đến nửa thước, trảo mang trong suốt có thể dễ dàng xé rách vòng bảo hộ của Tu Sĩ Kết Đan bình thường"}]},"nguon":["@c0799"]},{"id":"khoi-loi-quy-hinh","name":"Khôi Lỗi Quy hình","category":"phap-bao","categoryLabel":"Khôi Lỗi","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Khôi Lỗi hình rùa do Hàn Lập luyện chế, khoảng 15 khối, dùng yêu hồn cấp cao từ Loạn Tinh Hải.","detail":"Một trong hai loại Khôi Lỗi Hàn Lập luyện thành sau mấy tháng bế quan. Cần yêu thú tinh hồn cấp cao để luyện chế. Tổng hơn 30 khối gồm Quy hình và Hổ yêu, mỗi loại chiếm một nửa.","congNang":["Khôi lỗi chiến đấu hình rùa, dùng yêu hồn cấp cao điều khiển"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0800","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0800","loai":"xuất hiện","importance":"normal","giaiDoan":"Luyện chế hoàn tất","text":"Hàn Lập bế quan mấy tháng luyện thành khoảng 15 khối Khôi Lỗi Quy hình từ yêu hồn cấp cao lấy tại Loạn Tinh Hải.","anchor":"May mắn Hàn Lập lúc đầu tại Loạn Tinh Hải lấy được đại lượng yêu thú tinh hồn cấp cao nên mới có thể tiến hành thuận lợi"}]},"nguon":["@c0800"]},{"id":"khoi-loi-ho-yeu","name":"Khôi Lỗi Hổ yêu","category":"phap-bao","categoryLabel":"Khôi Lỗi","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Khôi Lỗi hình hổ yêu do Hàn Lập luyện chế, khoảng 15 khối.","detail":"Loại Khôi Lỗi thứ hai Hàn Lập luyện thành, hình thái hổ yêu. Cùng với Quy hình tổng hơn 30 khối, mỗi loại một nửa.","congNang":["Khôi lỗi chiến đấu hình hổ yêu"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0800","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0800","loai":"xuất hiện","importance":"normal","giaiDoan":"Luyện chế hoàn tất","text":"Hàn Lập luyện thành khoảng 15 khối Khôi Lỗi hình thái Hổ yêu, cùng đợt với Quy hình.","anchor":"Khôi Lỗi Quy hình cùng Khôi lỗ hình thái Hổ yêu, mỗi thứ chiếm một nửa"}]},"nguon":["@c0800"]},{"id":"noi-dan-hoa-thiem-co-thu","name":"Nội đan Hỏa Thiềm cổ thú","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"Chưa thu được","blurb":"Nội đan của Hỏa Thiềm cổ thú trong Trụy Ma Cốc, Hàn Lập yêu cầu làm điều kiện nhập cốc vì có tác dụng nhất định đối với hắn.","detail":"Hàn Lập đặt điều kiện nội đan Hỏa Thiềm cổ thú phải thuộc về mình khi đàm phán nhập Trụy Ma Cốc cùng Nam Lũng Hầu và Lỗ Vệ Anh. Hắn cố tỏ vẻ hời hợt, chỉ nói có một ít tác dụng, hai người dễ dàng đáp ứng vì coi nội đan vốn đương nhiên thuộc người ra tay tiêu diệt. Tác dụng cụ thể chưa được tiết lộ.","congNang":["Có tác dụng nhất định đối với Hàn Lập, cụ thể chưa rõ"],"chuSoHuu":[],"tabs":{"tienTrinh":[{"chuong":"@c0801","loai":"nhắc tới","importance":"normal","giaiDoan":"Đàm phán phân chia","text":"Hàn Lập yêu cầu nội đan Hỏa Thiềm cổ thú phải thuộc về mình làm điều kiện nhập Trụy Ma Cốc, Nam Lũng Hầu và Lỗ Vệ Anh đáp ứng.","anchor":"Nó có một ít tác dụng đối với tại hạ"}]},"nguon":["@c0801"]},{"id":"thuong-co-khoi-loi-cap","name":"Thượng cổ khôi lỗi (cặp)","cn":"","aliases":[],"category":"khac","categoryLabel":"Khôi lỗi","phamCap":"Thượng cổ","soHuu":["Đạo sĩ áo bào tro"],"trangThai":"dang-co","blurb":"Cặp khôi lỗi thượng cổ cao hai trượng, mặt mũi hung dữ, sức mạnh sánh được tu sĩ Nguyên Anh. Có thể thu nhỏ vào tay áo.","detail":"Hai thượng cổ khôi lỗi cao hai trượng, mặt mũi hung dữ, đứng phía sau đạo sĩ áo bào tro trên đỉnh núi. Sức mạnh có thể sánh với tu sĩ Nguyên Anh, được đạo sĩ thu nhỏ vào tay áo mang đi hướng Trụy Ma Cốc.","congNang":["Chiến đấu ngang tu sĩ Nguyên Anh"],"chuSoHuu":[{"ten":"Đạo sĩ áo bào tro","tuChuong":"@c0802","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0802","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện trên đỉnh núi cùng đạo sĩ áo bào tro","text":"Hai khôi lỗi thượng cổ cao hai trượng đứng phía sau đạo sĩ, được thu nhỏ vào tay áo rồi đưa đi hướng Trụy Ma Cốc.","anchor":"Được hai thượng cổ khôi lỗi có thể sánh với tu sĩ Nguyên Anh này trợ giúp, chuyến đi Trụy Ma Cốc lần này xem ra thu hoạch sẽ khá"}]},"nguon":["@c0802"]},{"id":"phi-xa-hinh-non-mo-lan","name":"Phi xa hình nón (Mộ Lan)","cn":"","aliases":[],"category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Nhạc thượng sư"],"trangThai":"dang-co","blurb":"Phi xa hình nón hơn hai mươi trượng, mặt ngoài phù chú dày đặc ngân quang lập lòe, dùng chở hơn mười pháp sĩ Mộ Lan đến Trụy Ma Cốc.","detail":"Xe bay hình nón hơn hai mươi trượng, mặt ngoài ngân quang lập lòe phù chú dày đặc ẩn hiển. Chở hơn mười pháp sĩ Mộ Lan. Sau khi hạ cánh, nữ tử họ Nhạc bắt quyết thu nhỏ.","congNang":["Vận chuyển nhóm đông qua không trung","Có thể thu nhỏ"],"chuSoHuu":[{"ten":"Nhạc thượng sư","tuChuong":"@c0802","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0802","loai":"xuất hiện","importance":"normal","giaiDoan":"Đoàn Mộ Lan đến Trụy Ma Cốc","text":"Phi xa hình nón chở hơn mười pháp sĩ Mộ Lan bay đến, hạ xuống gần lối vào Trụy Ma Cốc, được Nhạc thượng sư bắt quyết thu nhỏ.","anchor":"Hình nón, hơn hai mươi trượng, mặt ngoài lập lòe ngân quang, phù chú dày đặc ẩn hiển"}]},"nguon":["@c0802"]},{"id":"linh-thach-bac-cao-kim-hoang","name":"Linh thạch bậc cao kim hoàng sắc","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Linh thạch bậc cao","soHuu":["Quỷ Linh Môn","Vương Thiên Cổ"],"trangThai":"da-dung","blurb":"Khối linh thạch bậc cao kim chúc tính, trong suốt kim hoàng sắc, cực kỳ hiếm gần tuyệt tích tại Thiên Nam. Được Vương Thiên Cổ đặt vào trung tâm Đan Hướng Truyền Tống Trận để thúc dục pháp trận.","detail":"Linh thạch bậc cao chứa linh lực tương đương hơn trăm khối linh thạch bậc trung, nhưng giá trị thực tế gấp nghìn lần vì không thể dùng bậc trung đổi lấy. Mỏ quặng linh thạch bậc cao đã gần cạn kiệt, hiện chỉ ngẫu nhiên phát hiện khi khai thác mỏ bậc trung. Linh thạch đỉnh cấp nghe đồn đã biến mất từ thời thượng cổ. Dùng để thúc dục thượng cổ pháp trận, cấm chế, gia tăng uy lực pháp trận, bổ sung linh lực cho Nguyên Anh tu sĩ.","congNang":["Thúc dục thượng cổ pháp trận và cấm chế @c0803","Gia tăng uy lực pháp trận @c0803","Bổ sung linh lực cho Nguyên Anh tu sĩ @c0803"],"tabs":{"tienTrinh":[{"chuong":"@c0803","loai":"dùng","importance":"major","giaiDoan":"Đặt vào trung tâm Đan Hướng Truyền Tống Trận","text":"Vương Thiên Cổ cẩn thận lấy từ hộp ngọc, đặt vào trung tâm pháp trận. Tỏa linh khí kinh người khi lộ ra, các tu sĩ xung quanh thất kinh. Hàn Lập chưa từng thấy qua dù đánh chết nhiều tu sĩ.","anchor":"dùng tới ngàn khối Linh Thạch bậc trung để đổi một khối linh thạch bậc cao, tại tu tiên giới cũng là chưa từng nhìn thấy"}]},"nguon":["@c0803"]},{"id":"thach-an-tu-phuong","name":"Thạch ấn tứ phương","cn":"","aliases":["Thạch ấn pháp bảo"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại hán mặt đao"],"trangThai":"đang sử dụng","blurb":"Pháp bảo công kích hình tứ phương của đại hán mặt đao, to cỡ một tấc, đón gió phóng to cỡ một thước, phát hoàng quang, dùng để phá cấm chế bảy sắc thái hà trong ngoại cốc Trụy Ma Cốc.","detail":"Pháp bảo loại công kích, hình tứ phương, kích cỡ gốc một tấc. Có thể đón gió phóng to cỡ một thước, phát hoàng quang. Được đại hán mặt đao phun ra từ miệng và sử dụng làm vũ khí chính để phá cấm chế cổ đại trong ngoại cốc.","congNang":["Công kích phá cấm chế, phóng to theo ý chủ nhân"],"phanLoaiPhu":"Công kích","hinhDang":"Tứ phương hình, hoàng quang","chuSoHuu":[{"ten":"Đại hán mặt đao","tuChuong":"@c0805","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0805","loai":"dùng","importance":"normal","giaiDoan":"Phá cấm chế ngoại cốc","text":"Đại hán mặt đao phun ra thạch ấn tứ phương phóng to cỡ một thước, dùng làm vũ khí chính hợp lực phá cấm chế bảy sắc thái hà.","anchor":"bên trong bao lấy một viên tứ phương tiểu xảo thạch ấn to cỡ một tấc"}]},"nguon":["@c0805"]},{"id":"nhat-hong-nhat-bach-phi-kiem","name":"Nhất hồng nhất bạch phi kiếm","cn":"","aliases":["Hai khẩu phi kiếm hồng-bạch"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tu sĩ gò má cao","Tu sĩ diện mục ngăm đen"],"trangThai":"đang sử dụng","blurb":"Hai thanh phi kiếm một hồng một bạch của hai tu sĩ cẩm bào, tinh quang lấp lóe, dùng phụ trợ phá cấm chế trong ngoại cốc Trụy Ma Cốc.","detail":"Hai khẩu phi kiếm một hồng sắc một bạch sắc, tinh quang lấp lóe, mỗi người một thanh. Được hai tu sĩ cẩm bào thả ra phụ trợ đại hán mặt đao phá cấm chế bảy sắc thái hà.","nguon":["@c0805"]},{"id":"ao-choang-thanh-quang","name":"Áo choàng thanh quang","cn":"","aliases":["Áo choàng xanh"],"category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Đỉnh bậc linh khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Áo choàng thanh quang mà Hàn Lập cướp đoạt trước kia, công năng duy nhất là che khuất khuôn mặt ngăn người khác nhìn trộm hình dáng.","detail":"Vật cướp đoạt trước đây, đỉnh bậc linh khí. Công năng duy nhất: che khuất khuôn mặt, ngăn người khác nhìn trộm hình dáng. Cần linh lực liên tục rót vào để duy trì hiệu quả. Chỉ phòng được người có công lực không hơn người mang nhiều. Hàn Lập mang để giấu lam quang dị dạng khi thi triển Minh Thanh Linh Nhãn tại Trụy Ma Cốc.","congNang":["Che khuất khuôn mặt, ngăn người khác nhìn trộm hình dáng"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0806","denChuong":"","cachCoDuoc":"Cướp đoạt trước đây","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0806","loai":"dùng","importance":"normal","giaiDoan":"Hàn Lập mang vào tại Trụy Ma Cốc","text":"Hàn Lập lấy từ Túi Trữ Vật mang vào để che giấu lam quang dị dạng trong mắt khi thi triển Minh Thanh Linh Nhãn, phỏng đoán trừ Trọng Thần Sư và Ngụy Vô Nhai thì không ai nhìn thấu.","anchor":"có thể che khuất khuôn mặt, phòng ngừa người khác nhìn trộm hình dáng"}]},"nguon":["@c0806"]},{"id":"cam-ung-linh","name":"Cảm ứng linh","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu"],"trangThai":"đang sử dụng","blurb":"Chuông đồng nhiều màu lớn nhỏ cỡ vài tấc, treo bên hông, tự động rung khi gần khe hở không gian có ba động.","detail":"Vật phẩm của Nam Lũng Hầu, gồm nhiều cái chuông đồng màu sắc khác nhau. Tự động rung lên khi gần khe hở không gian có ba động hơi khác thường, dùng để cảnh báo nguy hiểm trên đường đi trong Trụy Ma Cốc. Tuy nhiên không phát hiện được khe hở không gian ẩn hình.","congNang":["Cảnh báo khe hở không gian có ba động"],"dacDiem":"Không phát hiện được khe hở không gian ẩn hình","chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0807","denChuong":"","cachCoDuoc":"Tự mang theo","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0807","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng trên đường đến nội cốc","text":"Nam Lũng Hầu treo cảm ứng linh bên hông để cảnh báo khe hở không gian khi ba người bay về phía nội cốc, nhưng Hàn Lập dùng linh nhãn phát hiện loại khe hở ẩn hình mà chuông không cảnh báo được.","anchor":"chỉ cần đến chỗ không gian có chút ba động hơi khác thường là nó tự động rung lên"}]},"nguon":["@c0807"]},{"id":"ngoc-boi-trang","name":"Ngọc bội trắng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu"],"trangThai":"đang sử dụng","blurb":"Vật của Thương Khôn Thượng Nhân để lại, có thể phá huyễn thuật thượng cổ che giấu cửa thông đạo bí mật vào nội cốc.","detail":"Khối ngọc bội màu trắng bắn ra từ cổ tay áo Nam Lũng Hầu, xoay quanh người rồi dừng trên đỉnh đầu. Hấp thu pháp quyết rồi phun ra ánh sáng trắng mờ, phá tan huyễn thuật mà Thương Khôn Thượng Nhân đã thi triển để che giấu cửa thông đạo bí mật dẫn vào nội cốc Trụy Ma Cốc.","congNang":["Phá huyễn thuật thượng cổ che giấu cửa thông đạo"],"nguonGoc":"Vật của Thương Khôn Thượng Nhân để lại","chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0807","denChuong":"","cachCoDuoc":"Thương Khôn Thượng Nhân để lại","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0807","loai":"dùng","importance":"normal","giaiDoan":"Phá huyễn thuật mở lối vào nội cốc","text":"Nam Lũng Hầu dùng ngọc bội trắng bắn ra pháp quyết, phun ánh sáng trắng mờ phá tan huyễn thuật che giấu cửa thông đạo bí mật, lộ ra lối vào nội cốc.","anchor":"một khối ngọc bội màu trắng từ trong cổ tay áo bắn ra"}]},"nguon":["@c0807"]},{"id":"cu-phong-ky","name":"Cự Phong Kỳ","cn":"","aliases":["Pháp kỳ (Lỗ Vệ Anh)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lỗ Vệ Anh"],"trangThai":"dang-co","blurb":"Pháp kỳ màu trắng quang hoa bắt mắt của Lỗ Vệ Anh, hóa thành cơn lốc hủy diệt mạnh mẽ.","detail":"Pháp kỳ trắng quang hoa bắt mắt thuộc sở hữu Lỗ Vệ Anh. Khi tế ra hóa thành bạch sắc cự phong (cơn lốc trắng) với sức mạnh hủy diệt khủng khiếp, chứa vô số phong nhận có thể băm nát cả tu sĩ Kết Đan lẫn pháp bảo cự thuẫn thành vạn đoạn. Cũng dùng để thổi tan yêu vụ.","congNang":["Hóa thành cự phong/cơn lốc chứa vô số phong nhận hủy diệt","Thổi tan yêu vụ"],"hinhDang":"Pháp kỳ màu trắng quang hoa bắt mắt","uyLuc":"Băm nát tu sĩ Kết Đan kỳ cùng pháp bảo cự thuẫn thành vạn đoạn trong nháy mắt","chuSoHuu":[{"ten":"Lỗ Vệ Anh","tuChuong":"@c0808","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0808","loai":"dùng","importance":"normal","giaiDoan":"Diệt khẩu Hoàng Thiên Minh tại thông đạo nội cốc","text":"Lỗ Vệ Anh tế Cự Phong Kỳ hóa bạch sắc cự phong, băm nát Hoàng Thiên Minh cùng cự thuẫn thành vạn đoạn. Chuẩn bị dùng tiếp để thổi tan yêu vụ cự mãng.","anchor":"pháp kỳ trong tay run lên tế ra ngoài. Pháp kỳ vừa ra tay hóa thành một đạo bạch sắc cự phong"}]},"capNhatToi":"@c0808","nguon":["@c0808"]},{"id":"thuong-co-an-hinh-phu","name":"Thượng cổ ẩn hình phù","cn":"","aliases":["ngọc phù kim sắc","ẩn hình ngọc phù"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (thượng cổ)","soHuu":["Hoàng Thiên Minh","Lỗ Vệ Anh"],"trangThai":"đổi chủ","blurb":"Ngọc phù kim sắc từ thượng cổ tu sĩ, giúp ẩn thân thần diệu đến mức khó phát hiện, nhưng vẫn bị Hàn Lập dùng linh nhãn nhìn thấu.","detail":"Ẩn hình phù thượng cổ dạng ngọc phù kim sắc, giúp người dùng ẩn thân thần diệu. Hoàng Thiên Minh — tu sĩ Kết Đan — dùng vật này theo dõi ba Nguyên Anh tu sĩ mà không bị phát hiện bằng thần thức thông thường. Tuy nhiên bị Hàn Lập dùng linh nhãn thần thông nhìn thấu. Sau khi Hoàng Thiên Minh bị giết, bị Lỗ Vệ Anh thu.","congNang":["Ẩn thân thần diệu, che giấu hình thể khỏi thần thức thông thường"],"chuSoHuu":[{"ten":"Hoàng Thiên Minh","tuChuong":"@c0808","denChuong":"@c0808","cachCoDuoc":"","trangThai":"mat"},{"ten":"Lỗ Vệ Anh","tuChuong":"@c0808","denChuong":"","cachCoDuoc":"Thu từ xác Hoàng Thiên Minh","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0808","loai":"đổi chủ","importance":"normal","giaiDoan":"Hoàng Thiên Minh bị giết, phù bị thu","text":"Hoàng Thiên Minh dùng ẩn hình phù theo dõi ba Nguyên Anh tu sĩ nhưng bị Hàn Lập phát hiện. Sau khi Lỗ Vệ Anh giết Hoàng Thiên Minh, thu ngọc phù này.","anchor":"bản thân hắn cũng bị vô số phong nhận trong cơn lốc băm thành vạn đoạn, chỉ còn một mảnh huyết vũ"}]},"capNhatToi":"@c0808","nguon":["@c0808"]},{"id":"kim-sac-phi-kiem","name":"Kim sắc phi kiếm","cn":"","aliases":["Kim sắc cự kiếm","Kim sắc tiểu kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bổn mạng pháp bảo","soHuu":["Nam Lũng Hầu"],"trangThai":"Bị cự mãng nuốt, cầm trụ trong bụng","blurb":"Bổn mạng pháp bảo của Nam Lũng Hầu, bồi luyện hơn trăm năm. Tâm thần tương liên với chủ nhân, pháp bảo hao tổn thì chủ cũng bị thương nặng.","detail":"Kim sắc phi kiếm là bổn mạng pháp bảo do Nam Lũng Hầu tiêu tốn hơn trăm năm bồi luyện. Có thể biến đổi kích cỡ giữa cự kiếm và tiểu kiếm. Do tính chất bổn mạng pháp bảo, tâm thần chủ nhân tương liên trực tiếp — nếu pháp bảo bị hao tổn thì chủ nhân khẳng định cũng sẽ bị thương nặng. Trong trận chiến với cự mãng (Tam Thủ Ô Xà), bị lục sắc linh quang hộ thể hất văng, sau đó bị cự mãng kéo dài thân nuốt gọn vào bụng, bị cầm trụ hoàn toàn không nhúc nhích dù chủ nhân cố thúc dục.","congNang":["Phi kiếm bổn mạng, tâm thần tương liên với chủ nhân"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0809","denChuong":"","cachCoDuoc":"Tự bồi luyện hơn trăm năm","trangThai":"bị cự mãng nuốt giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0809","loai":"dùng","importance":"major","giaiDoan":"Bị cự mãng nuốt mất","text":"Nam Lũng Hầu điều khiển tấn công cự mãng nhưng bị lục quang hộ thể hất văng. Cự mãng kéo dài thân nuốt gọn vào bụng cùng Kinh Long chung. Bị cầm trụ hoàn toàn không nhúc nhích, chủ nhân lo lắng vì tâm thần tương liên.","anchor":"bổn mạng pháp bảo mặc dù còn có thể liên lạc được nhưng giờ phút này bị cái gì trong bụng cự mãng cầm trụ"}]},"nguon":["@c0809"]},{"id":"bach-sac-hoa-cau-quy-di","name":"Bạch sắc hỏa cầu quỷ dị","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Phù lục","soHuu":["Lỗ Vệ Anh"],"trangThai":"Đang sử dụng","blurb":"Hơn mười khối hỏa cầu trắng chói mắt xuất hiện từ trương phù của Lỗ Vệ Anh, loại hỏa cầu mà Hàn Lập mơ hồ nhớ đã từng nghe nói qua.","detail":"Bạch sắc hỏa cầu quỷ dị là loại hỏa cầu sáng trắng chói mắt được triệu xuất từ trương phù. Lỗ Vệ Anh bắn ra hơn mười khối khi chuyển sang chiến thuật mới sau khi pháp kỳ không còn hiệu quả. Hàn Lập mơ hồ cảm giác đã nghe nói qua về loại hỏa cầu này nhưng không nhớ rõ, ám chỉ nguồn gốc không tầm thường.","nguon":["@c0809"]},{"id":"nhan-xanh-biec","name":"Nhẫn xanh biếc","cn":"","aliases":["ngọc hoàn lục sắc","chiếc nhẫn xanh biếc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Chiếc nhẫn xanh biếc của Nam Lũng Hầu, có thể huyễn hóa thành hơn trăm bản sao đánh lừa đối thủ, bản thể co rút ghìm chặt vào vị trí thất thốn để cấm chế mục tiêu.","detail":"Pháp bảo dạng nhẫn bích lục sắc. Khi thi triển huyễn hóa thành hơn trăm chiếc nhẫn giả, bản thể xẹt qua biến thành quang ảnh bích lục. Có khả năng co rút lại ghìm chặt vào vị trí yếu huyệt (thất thốn) dưới đầu đối thủ, dấn sâu vào da thịt khiến mục tiêu đau đớn quay cuồng, bị chế trụ tại chỗ. Sau trận đánh khôi phục nguyên hình đeo lại ngón tay chủ nhân.","congNang":["Huyễn hóa nhiều bản sao nhẫn để đánh lừa đối thủ @c0810","Co rút ghìm chặt vào vị trí yếu huyệt cấm chế mục tiêu @c0810"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0810","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0810","loai":"dùng","importance":"normal","giaiDoan":"Trận diệt tam thủ cự mãng","text":"Nam Lũng Hầu phóng nhẫn huyễn hóa hơn trăm cái, bản thể ghìm chặt vị trí thất thốn dưới đầu cự mãng chế trụ nó, phối hợp cùng Thiên Trọng Phong nghiền nát cự mãng.","anchor":"một hóa hai, hai hóa bốn, bốn hóa tám"}]},"nguon":["@c0810"]},{"id":"thanh-sac-noi-dan","name":"Thanh sắc nội đan","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Hàn Lập","Nam Lũng Hầu","Lỗ Vệ Anh"],"trangThai":"dang-co","blurb":"Ba viên nội đan thanh sắc to cỡ ngón cái lấy từ ba đầu của tam thủ cự mãng, mỗi người chia một viên.","detail":"Nội đan thanh sắc, kích thước to cỡ ngón cái, lấy từ ba đầu rắn của tam thủ cự mãng trong Trụy Ma Cốc. Lỗ Vệ Anh khai thác và chia đều, mỗi người nhận một viên.","nguon":["@c0810"]},{"id":"cuong-ngan-sa","name":"Cương Ngân Sa","cn":"剛銀砂","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cực phẩm (gần bằng Luyện Tinh)","soHuu":["Hàn Lập"],"trangThai":"dang-khai-thac","blurb":"Tài liệu luyện khí cực cứng, có thể khảm vào pháp bảo gia tăng độ chắc chắn, hiệu quả chỉ thấp hơn Luyện Tinh một chút. Gần như tuyệt tích ở cả Loạn Tinh Hải và Thiên Nam.","detail":"Mỏ quặng tự nhiên được phát hiện trong thạch bích cửa động Trụy Ma Cốc, mật độ không đều, hình thành tự nhiên chứ không phải nhân tạo. Bản thân cực cứng, pháp bảo thường khó tổn thương. Có thể khảm vào pháp bảo gia tăng độ chắc chắn hoặc trộn vào thân thể khôi lỗi khiến pháp bảo bình thường không tổn thương được. Khai thác rất khó — một khối quặng to bằng nắm tay chỉ tinh luyện ra hạt nhỏ như hạt gạo. Đại Diễn Thần Quân muốn dùng luyện chế khôi lỗi mới.","congNang":["Khảm vào pháp bảo gia tăng độ chắc chắn, hiệu quả gần bằng Luyện Tinh @c0811","Trộn vào thân thể khôi lỗi khiến pháp bảo bình thường không tổn thương được @c0811"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0811","denChuong":"","cachCoDuoc":"Dùng Phệ Kim Trùng khai thác trong thạch bích Trụy Ma Cốc","trangThai":"dang-khai-thac"}],"tabs":{"tienTrinh":[{"chuong":"@c0811","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện mỏ quặng","phamCap":"Cực phẩm nguyên liệu","text":"Lỗ Vệ Anh chém thạch bích lộ ra ngân quang, nhận ra Cương Ngân Sa. Hàn Lập dùng phi kiếm xác nhận cả tòa thạch bích chứa mỏ quặng mật độ không đều, hình thành tự nhiên. Đại Diễn Thần Quân muốn dùng trộn vào khôi lỗi mới. Hàn Lập bí mật phóng thích Phệ Kim Trùng vào thạch bích khai thác.","anchor":"Cương Ngân Sa? Trong thạch bích này có quặng mỏ Cương Ngân Sa!"}]},"nguon":["@c0811"]},{"id":"khoi-loi-thuong-co-thien-tinh","name":"Khôi lỗi thượng cổ (Thiên Tinh Chân Nhân)","cn":"","category":"khac","categoryLabel":"Khôi lỗi","phamCap":"Nguyên Anh Sơ Kỳ","soHuu":["Thiên Tinh Chân Nhân"],"trangThai":"dang-dung","blurb":"Hai con Khôi lỗi bộ dáng ác quỷ thời thượng cổ, do Thiên Tinh Chân Nhân luyện chế từ Hồn Thạch, mỗi con thực lực Nguyên Anh Sơ Kỳ.","detail":"Hai con Khôi lỗi bộ dáng ác quỷ thời thượng cổ, được Thiên Tinh Chân Nhân luyện chế từ Hồn Thạch (giao dịch với Hàn Lập trước đó). Mỗi con đều có thực lực Nguyên Anh Sơ Kỳ, ngay cả Thiên Tinh Chân Nhân muốn đối phó cũng vất vả. Là chiêu bài giúp hắn dám vào Trụy Ma Cốc.","nguonGoc":"Luyện chế từ Hồn Thạch do Hàn Lập cung cấp","uyLuc":"Mỗi con thực lực Nguyên Anh Sơ Kỳ","dacDiem":"Bộ dáng ác quỷ, thời thượng cổ","congNang":["Chiến đấu thay chủ nhân với thực lực Nguyên Anh Sơ Kỳ"],"chuSoHuu":[{"ten":"Thiên Tinh Chân Nhân","tuChuong":"@c0812","denChuong":"","cachCoDuoc":"Tự luyện chế từ Hồn Thạch","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0812","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện cùng Thiên Tinh Chân Nhân trước hạp cốc","text":"Hai con Khôi lỗi thượng cổ bộ dáng ác quỷ đứng sau Thiên Tinh Chân Nhân trước hạp cốc lớn, được xác nhận luyện từ Hồn Thạch giao dịch với Hàn Lập, mỗi con thực lực Nguyên Anh Sơ Kỳ.","anchor":"Hai ác quỷ Khôi lỗi thời thượng cổ phía sau cũng là do lợi dụng Hồn Thạch mới luyện chế thành, mỗi con đều có thực lực Nguyên Anh Sơ Kỳ"}]},"nguon":["@c0812"]},{"id":"yeu-dan-hoa-thiem-thu","name":"Yêu đan Hỏa Thiềm thú","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập thu giữ","blurb":"Yêu đan của Hỏa Thiềm cổ thú trong nội cốc Trụy Ma Cốc, là một trong các mục tiêu chính của Hàn Lập khi thâm nhập nội cốc.","detail":"Yêu đan nằm trong cơ thể Hỏa Thiềm thú tại nội cốc Trụy Ma Cốc. Hàn Lập coi đây là mục tiêu thu hoạch hàng đầu của chuyến vào nội cốc, bên cạnh bảo vật bên hài cốt cổ tu sĩ, Linh Chúc quả và Cương Ngân Sa.","tabs":{"tienTrinh":[{"chuong":"@c0813","loai":"nhac-toi","importance":"bridge","giaiDoan":"Được Hàn Lập xác định là mục tiêu chính","text":"Hàn Lập coi yêu đan Hỏa Thiềm thú là một trong các mục tiêu chính khi vào nội cốc.","anchor":"lần này vào cốc có thể lấy được yêu đan của Hỏa Thiềm cùng bảo vật lưu lại bên hài cốt cổ tu sĩ kia"},{"chuong":"@c0818","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ ra và được Hàn Lập thu","text":"Yêu đan đỏ rực lộ ra sau khi Hỏa Thiềm thú bị phá hủy hoàn toàn. Nam Lũng Hầu và Lỗ Vệ Anh động tâm nhưng bỏ ý, Hàn Lập thu lấy.","anchor":"Dù sao đấy cũng là yêu đan của cổ thú có bất diệt chi thể, nói không chừng còn có hiệu quả đặc thù gì đó"}]},"nguon":["@c0813","@c0818"],"congNang":["Chưa rõ, nghi có hiệu quả đặc thù do là yêu đan cổ thú có Bất diệt chi thể"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0818","denChuong":"","cachCoDuoc":"Thu sau khi diệt Hỏa Thiềm thú","trangThai":"dang-co"}]},{"id":"bich-cuu","name":"Bích Cưu","cn":"碧蚯","category":"dan-duoc","categoryLabel":"Đan dược / Độc dược","phamCap":"Thập Tuyệt độc (cực độc)","soHuu":["Hàn Lập"],"trangThai":"đã dùng một phần","blurb":"Một trong Thập Tuyệt độc, luyện từ dãi yêu cầm Bích Chủy Cưu, cực độc và có mùi cay khiến đại độc trùng ưa thích, dùng để dẫn dụ Phi Thiên Tử Vân hạt.","detail":"Bích Cưu là một trong mười loại cực độc nổi tiếng nhất tu tiên giới (Thập Tuyệt độc), được luyện từ dãi của yêu cầm Bích Chủy Cưu. Ngoài độc tính chết người, Bích Cưu còn tỏa mùi cay đặc biệt khiến đại độc trùng cực kỳ ưa thích. Đựng trong bình nhỏ xanh biếc, vốn nằm trong hộp bảo vật mà Thương Khôn Thượng Nhân đã chuẩn bị sẵn cho hành trình Trụy Ma Cốc. Hàn Lập lấy ra nhỏ vào bình ngọc nhỏ giao cho khôi lỗi mang đi dẫn dụ Phi Thiên Tử Vân hạt rời khỏi đường đi.","congNang":["Cực độc, tu tiên giả trúng phải lập tức bỏ mạng","Mùi cay đặc biệt hấp dẫn đại độc trùng, dùng làm mồi dẫn dụ","Khắc chế, dẫn dụ độc trùng Tử Vân hạt khi tẩm vào khôi lỗi làm mồi (@c0815)"],"nguonGoc":"Luyện từ dãi yêu cầm Bích Chủy Cưu, nằm trong hộp bảo vật Thương Khôn Thượng Nhân","hinhDang":"Đựng trong bình nhỏ xanh biếc","chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"@c0814","denChuong":"","cachCoDuoc":"Tự chuẩn bị sẵn","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0814","denChuong":"","cachCoDuoc":"Lấy từ hộp bảo vật Thương Khôn Thượng Nhân","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0814","loai":"dùng","importance":"major","giaiDoan":"Dẫn dụ Phi Thiên Tử Vân hạt","phamCap":"Thập Tuyệt độc","text":"Hàn Lập lấy Bích Cưu từ hộp bảo vật Thương Khôn Thượng Nhân, nhỏ độc dịch vào bình ngọc giao khôi lỗi mang lên đỉnh núi bóp nát phóng thích mùi cay dẫn dụ đám Phi Thiên Tử Vân hạt rời khỏi đường đi.","anchor":"Trong bình này chính là Bích Cưu một trong Thập Tuyệt độc"},{"chuong":"@c0815","loai":"dùng","importance":"normal","text":"Được tẩm vào khôi lỗi cự viên dụ đàn Tử Vân hạt rời tổ, là công thần giúp ba người vượt ải. Hàn Lập giấu đồng bạn nguồn gốc là bảo vật Thương Khôn Thượng Nhân để lại.","anchor":"Lần này tất cả là nhờ vào Bích Cưu độc cùng khôi lỗi của Hàn huynh"}]},"nguon":["@c0814","@c0815"],"aliases":["Bích Cưu"]},{"id":"thap-tuyet-doc","name":"Thập Tuyệt độc","cn":"十绝毒","category":"khac","categoryLabel":"Hệ thống phân loại","phamCap":"Cực độc","soHuu":[],"trangThai":"","blurb":"Mười loại cực độc nổi tiếng nhất tu tiên giới, tu tiên giả trúng phải có thể lập tức bỏ mạng, ngoài độc tính còn có diệu dụng khác.","detail":"Thập Tuyệt độc là mười thứ cực độc nổi tiếng trong tu tiên giới. Ngoài độc tính chết người, mỗi loại còn có diệu dụng riêng. Đã biết hai loại: Bích Cưu (luyện từ dãi yêu cầm Bích Chủy Cưu, có mùi cay dẫn dụ đại độc trùng) và Phúc Thi chi độc (do Ngụy Vô Nhai chủ tu độc công sinh ra, khiến tu sĩ khác không dám tiếp cận trong mười trượng).","nguon":["@c0814"]},{"id":"phuc-thi-chi-doc","name":"Phúc Thi chi độc","cn":"腹蛇之毒","aliases":["Độc rắn"],"category":"dan-duoc","categoryLabel":"Đan dược / Độc dược","phamCap":"Thập Tuyệt độc (cực độc)","soHuu":["Ngụy Vô Nhai"],"trangThai":"","blurb":"Một trong Thập Tuyệt độc, do Ngụy Vô Nhai chủ tu độc công sinh ra, khiến tu sĩ khác không dám tiếp cận trong phạm vi mười trượng.","detail":"Phúc Thi chi độc (còn gọi là độc rắn) là một trong Thập Tuyệt độc, được sinh ra từ độc công mà Ngụy Vô Nhai chủ tu. Khi đánh nhau, tu sĩ khác không dám tiếp cận hắn trong phạm vi mười trượng vì mức độ kịch độc lan tỏa.","congNang":["Kịch độc lan tỏa phạm vi mười trượng xung quanh người tu"],"chuSoHuu":[{"ten":"Ngụy Vô Nhai","tuChuong":"@c0814","denChuong":"","cachCoDuoc":"Tự sinh ra từ độc công chủ tu","trangThai":"dang-co"}],"nguon":["@c0814"]},{"id":"ky-trung-bang","name":"Kỳ Trùng bảng","cn":"奇虫榜","category":"khac","categoryLabel":"Tài liệu / Ngọc giản","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bảng xếp hạng các loại kỳ trùng hung ác, Phi Thiên Tử Vân hạt đứng thứ 14 ngay sau Phệ Kim Trùng. Hàn Lập lấy được từ tu sĩ Ngự Linh Tông đã chết.","detail":"Kỳ Trùng bảng là ngọc giản ghi chép xếp hạng các loại kỳ trùng hung ác. Phi Thiên Tử Vân hạt đứng ở vị trí thứ mười bốn, bám sát sau Phệ Kim Trùng. Ngọc giản này lấy từ tu sĩ Ngự Linh Tông đã chết trong tay Hàn Lập.","nguon":["@c0814"]},{"id":"khoi-loi-bach-lang","name":"Khôi lỗi bạch lang","cn":"","category":"linh-khi","categoryLabel":"Khôi lỗi","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phân thân khôi lỗi thú loại tốc độ do Hàn Lập điều khiển, dùng thăm dò hang Hỏa Thiềm Thú rồi bị yêu hỏa thiêu hủy hoàn toàn.","detail":"Khôi lỗi thú mang tính tốc độ, được Hàn Lập dùng tiến vào thông đạo hang động thăm dò Hỏa Thiềm Thú và di hài tu sĩ cổ. Sau đó làm mồi dẫn dụ cổ thú ra ngoài. Khi sắp tới pháp trận, bị Hỏa Thiềm Thú phun hỏa cầu phình to thành cơn gió lửa thiêu hủy hoàn toàn.","congNang":["Trinh sát thăm dò","Dẫn dụ mục tiêu"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0816","denChuong":"@c0816","cachCoDuoc":"Tự luyện chế","trangThai":"bị hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c0815","loai":"dùng","importance":"normal","text":"Con khôi lỗi hình bạch lang còn sót lại được Hàn Lập lấy từ túi linh thú, thao túng bay về phía sơn động dụ Hỏa Thiềm thú ra khỏi sào huyệt.","anchor":"một con khôi lỗi hình bạch lang (sói trắng) còn sót lại bỗng xuất hiện"},{"chuong":"@c0816","loai":"dùng","importance":"normal","giaiDoan":"Thăm dò và dẫn dụ","text":"Hàn Lập điều khiển bạch lang khôi lỗi vào hang thăm dò, phát hiện Hỏa Thiềm Thú và di hài. Bị cổ thú truy đuổi, thiêu hủy hoàn toàn trước khi kịp vào pháp trận.","anchor":"khôi lỗi thú đã bị tiêu diệt vô ảnh vô tung"}]},"nguon":["@c0816","@c0815"]},{"id":"sau-khoi-loi-cu-quy","name":"Sáu khôi lỗi cự quy","cn":"","category":"linh-khi","categoryLabel":"Khôi lỗi","phamCap":"Kết Đan Kỳ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Sáu con khôi lỗi cự quy mới luyện chế, thân cao ba trượng, mai mọc băng trùy dài một thước tỏa hàn khí, phun băng trùy công kích.","detail":"Hàn Lập mới luyện chế, thân cao ba trượng, trên quy xác mọc ra băng trùy dài một thước sắc nhọn tỏa hàn khí, hình dáng cực kỳ hung ác. Phun băng trùy đối kháng hỏa cầu Hỏa Thiềm Thú, tạm ngăn được hỏa lãng nhưng uy lực kém hơn yêu hỏa.","congNang":["Phun băng trùy công kích viễn trình hàn băng"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0816","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0816","loai":"xuất hiện","importance":"normal","giaiDoan":"Giao đấu Hỏa Thiềm Thú","text":"Hàn Lập triệu ra sáu khôi lỗi cự quy mới luyện giao đấu Hỏa Thiềm Thú, phun băng trùy đối kháng hỏa cầu nhưng uy lực kém hơn yêu hỏa.","anchor":"xuất hiện sáu con rùa to lớn, thân cao ba trượng, linh quang toàn thân lấp lóe"}]},"nguon":["@c0816"]},{"id":"bich-ngoc-chi-hoan","name":"Bích ngọc chỉ hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Chiếc nhẫn ngọc bích của Nam Lũng Hầu, ném ra tấn công Hỏa Thiềm Thú xuyên qua quang mạc pháp trận.","detail":"Pháp bảo hình nhẫn ngọc bích, Nam Lũng Hầu ném ra tấn công viễn trình, xuyên qua quang mạc pháp trận công kích vòng bảo vệ quang thuẫn đỏ của Hỏa Thiềm Thú.","congNang":["Công kích viễn trình"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0816","denChuong":"","cachCoDuoc":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0816","loai":"dùng","importance":"normal","giaiDoan":"Hợp kích Hỏa Thiềm Thú","text":"Nam Lũng Hầu ném bích ngọc chỉ hoàn tấn công vòng bảo vệ Hỏa Thiềm Thú trong pháp trận.","anchor":"Nam Lũng Hầu ném bích ngọc chỉ hoàn ra"}]},"nguon":["@c0816"]},{"id":"hai-thanh-phi-qua","name":"Hai thanh phi qua","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lỗ Vệ Anh"],"trangThai":"dang-co","blurb":"Hai thanh thương/giáo của Lỗ Vệ Anh, dùng thay pháp kỳ để tấn công Hỏa Thiềm Thú.","detail":"Lỗ Vệ Anh không dùng pháp kỳ như trước mà giương hai thanh phi qua bắn xuyên quang mạc tấn công Hỏa Thiềm Thú trong pháp trận.","congNang":["Công kích viễn trình"],"chuSoHuu":[{"ten":"Lỗ Vệ Anh","tuChuong":"@c0816","denChuong":"","cachCoDuoc":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0816","loai":"dùng","importance":"normal","giaiDoan":"Hợp kích Hỏa Thiềm Thú","text":"Lỗ Vệ Anh giương hai thanh phi qua bắn tới tấn công Hỏa Thiềm Thú thay vì dùng pháp kỳ.","anchor":"hai thanh phi qua đồng loạt bắn tới"}]},"nguon":["@c0816"]},{"id":"truong-bao-xanh-co-xua","name":"Trường bào xanh cổ xưa","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (phi phàm)","soHuu":["Di hài tu sĩ cổ"],"trangThai":"dang-co","blurb":"Áo trường bào kiểu cổ trên di hài tu sĩ, trải thời gian dài vẫn mới tinh tỏa lục quang, tự động bùng linh quang ngăn cản thần thức thăm dò.","detail":"Trường bào xanh kiểu cổ không giống tu sĩ ngày nay, mặc trên di hài trên thạch thai trong hang Hỏa Thiềm Thú, vẫn mới tinh tỏa lục quang nhàn nhạt. Khi Hàn Lập dùng tia phân thần thăm dò, trường bào bùng linh quang đại thịnh phát ra tầng ánh sáng mờ ngăn cản thần thức, dao động linh khí đánh thức Hỏa Thiềm Thú.","congNang":["Tự động phòng hộ chống thăm dò thần thức"],"nguon":["@c0816"]},{"id":"thanh-truc-phong-van-kiem","name":"Thanh Trúc Phong Vân kiếm","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng phẩm pháp bảo (đã thêm Canh Tinh)","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Bộ phi kiếm vàng gồm hơn mười thanh, có thể hợp nhất thành cự kiếm dài hơn một trượng, đã được thêm Canh Tinh nên sắc bén phi thường.","detail":"Hơn mười thanh phi kiếm vàng hợp nhất thành cự kiếm dài hơn một trượng, tỏa hào quang rực rỡ hàn khí bức người. Có thể kết hợp Cực Hàn lam diễm và Ích Tà Thần Lôi phủ lên thân kiếm. Đã được thêm Canh Tinh nên sắc bén đến mức chém đứt lưỡi Hỏa Thiềm thú cứng như pháp bảo, pháp bảo bình thường không thể so sánh.","congNang":["Hợp nhất hơn mười thanh thành cự kiếm dài hơn một trượng","Kết hợp Cực Hàn lam diễm đông kết quang thuẫn hỏa thuộc tính","Kết hợp Ích Tà Thần Lôi tạo điện võng phòng ngự phản kích","Đã thêm Canh Tinh — sắc bén phi thường, chém đứt lưỡi yêu thú cứng như pháp bảo"],"uyLuc":"Trảm thủ thượng cổ kỳ thú cấp Nguyên Anh, phá mười lớp quang thuẫn liên tiếp","dacDiem":"Đã thêm Canh Tinh, sắc bén vượt xa pháp bảo thường","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0817","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0817","loai":"dùng","importance":"major","giaiDoan":"Trảm đầu Hỏa Thiềm thú","phamCap":"Thượng phẩm (đã thêm Canh Tinh)","text":"Hơn mười thanh phi kiếm vàng hợp nhất thành cự kiếm, phủ Cực Hàn lam diễm và Ích Tà Thần Lôi, phá mười lớp quang thuẫn liên tiếp rồi trảm đầu Hỏa Thiềm thú. Lưỡi yêu thú cứng như pháp bảo quấn lấy kiếm nhưng bị chém đứt đôi nhờ đã thêm Canh Tinh.","anchor":"Thanh Trúc Phong Vân kiếm đã được thêm vào Canh Tinh, pháp bảo bình thường sao có thể so sánh được"}]},"nguon":["@c0817"]},{"id":"thanh-tam-bao","name":"Thanh Tàm bào","cn":"青蚕袍","category":"phap-bao","categoryLabel":"Pháp bảo (y phục)","phamCap":"Cổ bảo","soHuu":["Nam Lũng Hầu"],"trangThai":"Nam Lũng Hầu thu giữ","blurb":"Áo bào dệt từ tơ tằm cổ xưa, có thể ngăn cản thần thức tu sĩ dò xét. Thời thượng cổ chỉ là vật bình thường, hiện tại là bảo vật hiếm.","detail":"Mặc trên hài cốt cổ tu sĩ trong sào huyệt Hỏa Thiềm thú. Khi Nam Lũng Hầu và Lỗ Vệ Anh dùng thần thức tra xét hài cốt, bị thanh bào phản xạ lại. Nam Lũng Hầu nhận ra đây là Thanh Tàm bào dệt từ loại tơ tằm cổ xưa, thời thượng cổ chỉ là vật bình thường nhưng hiện tại rất hiếm trong tu tiên giới.","congNang":["Ngăn cản thần thức tu sĩ dò xét, phản xạ thần thức"],"hinhDang":"Áo bào thanh sắc","vatLieu":"Tơ tằm cổ xưa","nguonGoc":"Di vật trên hài cốt cổ tu sĩ trong sào huyệt Hỏa Thiềm thú, Trụy Ma Cốc","chuSoHuu":[{"ten":"Cổ tu sĩ (hài cốt)","tuChuong":"@c0818","denChuong":"@c0818","cachCoDuoc":"Mặc trên người","trangThai":"da-mat"},{"ten":"Nam Lũng Hầu","tuChuong":"@c0818","denChuong":"","cachCoDuoc":"Thu từ hài cốt cổ tu sĩ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0818","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện trên hài cốt, Nam Lũng Hầu thu","text":"Thanh bào phản xạ thần thức khiến hai tu sĩ không thể dò xét hài cốt. Nam Lũng Hầu nhận ra là Thanh Tàm bào dệt từ tơ tằm cổ xưa và thu lấy.","anchor":"Loại áo này được dệt từ một loại tơ tằm cổ xưa, có thể ngăn cản thần thức tu sĩ dò xét"}]},"nguon":["@c0818"]},{"id":"linh-lieu","name":"Linh liệu","cn":"灵料","category":"nguyen-lieu","categoryLabel":"Nguyên liệu luyện khí","phamCap":"Cổ đại trân quý","soHuu":[],"trangThai":"Chưa phân chia","blurb":"Nhiều khối sắt đỏ tỏa hồng quang, là tài liệu cổ dùng luyện chế cổ bảo, bán thành phẩm kết hợp tài liệu trân quý với thiên địa chi lực.","detail":"Nằm trong túi trữ vật cổ tu sĩ. Nam Lũng Hầu nhận ra đây là linh liệu truyền thuyết — phương pháp luyện đặc thù: dùng tài liệu trân quý kết hợp thiên địa chi lực tạo thành, thuộc dạng bán thành phẩm đã qua tế luyện. Cổ tu sĩ mang nhiều để luyện cổ bảo Hỏa thuộc tính. Lỗ Vệ Anh không hứng thú lắm với linh liệu.","congNang":["Tài liệu dùng luyện chế cổ bảo, Hỏa thuộc tính"],"tabs":{"tienTrinh":[{"chuong":"@c0818","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện trong túi trữ vật cổ tu sĩ","text":"Nam Lũng Hầu đổ ra nhiều khối sắt đỏ tỏa hồng quang từ túi trữ vật, nhận ra là linh liệu truyền thuyết dùng luyện cổ bảo.","anchor":"những khối sắt kia chính là “linh liệu” trong truyền thuyết mà cổ tu sĩ dùng để luyện chế cổ bảo"}]},"nguon":["@c0818"]},{"id":"that-diem-phien","name":"Thất Diễm phiến","cn":"七焰扇","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thông Thiên Linh Bảo (vị trí rất thấp, gần đội sổ)","soHuu":["Hàn Lập"],"trangThai":"chưa luyện chế","blurb":"Một loại Thông Thiên Linh Bảo cần 81 loại tài liệu Hỏa thuộc tính cùng nhiều linh liệu hiếm để luyện chế. Ngọc giản ghi phương pháp luyện chế được Hàn Lập lấy được khi phân chia bảo vật.","detail":"Ngọc giản màu vàng đất bên trong hộp ngọc trắng có cấm chế bạch quang, ghi chép phương pháp luyện chế Thất Diễm phiến. Cần 81 loại tài liệu Hỏa thuộc tính và nhiều linh liệu hiếm, trong đó nhiều loại đã tuyệt tích. Nam Lũng Hầu và Lỗ Vệ Anh đánh giá ít giá trị thực tế, chỉ dùng nghiên cứu luyện khí. Ngân Nguyệt nhận ra đây là Thông Thiên Linh Bảo đứng vị trí rất thấp, gần đội sổ. Đại Diễn Thần Quân hưng phấn muốn nghiên cứu.","hinhDang":"Ngọc giản màu vàng đất (phương pháp luyện chế); hình dạng thành phẩm chưa rõ","nguonGoc":"Tìm thấy trong hộp ngọc trắng có cấm chế bạch quang","dacDiem":"Cần 81 loại tài liệu Hỏa thuộc tính và nhiều linh liệu hiếm (nhiều loại đã tuyệt tích) để luyện chế","congNang":["Chưa rõ công năng cụ thể (chưa luyện chế)"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0819","denChuong":"","cachCoDuoc":"Phân chia bảo vật, dùng mưu kế lấy được","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0819","loai":"xuat-hien","importance":"major","giaiDoan":"Phát hiện ngọc giản luyện chế","text":"Nam Lũng Hầu mở hộp ngọc trắng phá cấm chế bạch quang, phát hiện ngọc giản ghi phương pháp luyện chế Thất Diễm phiến. Ngân Nguyệt nhận ra đây là Thông Thiên Linh Bảo. Hàn Lập dùng mưu kế đàm phán lấy được ngọc giản.","phamCap":"Thông Thiên Linh Bảo (vị trí rất thấp)","anchor":"nó là một loại Thông Thiên Linh Bảo, chỉ là nó đứng ở vị trí rất thấp, gần như là đội sổ"},{"chuong":"@c0821","loai":"xuất hiện","importance":"normal","giaiDoan":"Giao tài liệu nghiên cứu","text":"Hàn Lập giao tài liệu luyện chế Thất Diễm Phiến cho Đại Diễn Thần Quân, thách lão tìm phương pháp thay thế vật liệu đã tuyệt diệt.","anchor":"Tài liệu luyện chế Thất Diễm Phiến không ít thứ đã sớm bị tuyệt diệt, hoặc là căn bản khó có thể tìm được"}]},"capNhatToi":"@c0819","dinhDanh":"goc","nguon":["@c0819","@c0821"]},{"id":"co-linh-dan-xanh-biec","name":"Cổ linh đan xanh biếc","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cổ linh đan thượng cổ (chưa rõ phẩm cấp cụ thể)","soHuu":["Nam Lũng Hầu","Lỗ Vệ Anh"],"trangThai":"Mỗi người một viên","blurb":"Hai viên cổ linh đan thượng cổ màu xanh biếc tỏa thanh hương, mỗi viên nằm trong một dược bình. Nam Lũng Hầu và Lỗ Vệ Anh mỗi người lấy một viên.","detail":"Hai dược bình mỗi cái chứa một viên dược hoàn màu xanh biếc, tỏa thanh hương khiến tinh thần thư thái. Nam Lũng Hầu nhận định đây là cổ linh đan thượng cổ rất hiếm, không phải độc dược, chưa xác định tên chính xác. Cả hai đều rất cần linh đan vì sắp hết thọ nguyên.","dacDiem":"Màu xanh biếc, tỏa thanh hương khiến tinh thần thư thái","congNang":["Chưa rõ tác dụng cụ thể, nghi liên quan thọ nguyên hoặc tu vi"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0819","denChuong":"","cachCoDuoc":"Phân chia bảo vật","trangThai":"dang-co"},{"ten":"Lỗ Vệ Anh","tuChuong":"@c0819","denChuong":"","cachCoDuoc":"Phân chia bảo vật","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0819","loai":"xuat-hien","importance":"normal","giaiDoan":"Phát hiện trong dược bình","text":"Nam Lũng Hầu mở hai dược bình, phát hiện mỗi bình chứa một viên dược hoàn xanh biếc tỏa thanh hương, nhận định là cổ linh đan thượng cổ rất hiếm. Hai người mỗi người lấy một viên.","anchor":"Hình như đây là một loại linh đan thượng cổ rất khó gặp"}]},"capNhatToi":"@c0819","dinhDanh":"goc","nguon":["@c0819"]},{"id":"co-kinh-tim","name":"Cổ kính tím","aliases":["Kính tím"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo (chưa rõ phẩm cấp cụ thể)","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập sở hữu","blurb":"Một kiện cổ bảo màu tím, chưa rõ công năng. Hàn Lập chọn lấy khi phân chia bảo vật.","detail":"Một trong ba kiện cổ bảo trên mặt đất. Hàn Lập chọn lấy chiếc kính màu tím khi phân chia bảo vật với Nam Lũng Hầu và Lỗ Vệ Anh. Công năng chưa được hé lộ.","dacDiem":"Màu tím","congNang":["Chưa rõ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0819","denChuong":"","cachCoDuoc":"Phân chia bảo vật, tự chọn lấy","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0819","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập chọn lấy","text":"Hàn Lập chọn lấy chiếc cổ kính tím khi phân chia bảo vật với Nam Lũng Hầu và Lỗ Vệ Anh.","anchor":"cái kính kia, còn lại là muốn ngọc giản và linh liệu"}]},"capNhatToi":"@c0819","dinhDanh":"goc","nguon":["@c0819"]},{"id":"dia-do-truy-ma-coc","name":"Địa đồ Trụy Ma Cốc","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Mảnh vải vẽ sơ đồ Trụy Ma Cốc có tiêu ký thô to bắt mắt, giấu bên trong lớp vải Thanh Tàm bào.","detail":"Mảnh vải không giống vải chẳng giống lụa, dùng bút than vẽ sơ đồ đơn giản của Trụy Ma Cốc, trên đó có một tiêu ký thô to rất bắt mắt gợi ý vị trí quan trọng. Được Hàn Lập phát hiện khi xé góc Thanh Tàm bào mà Nam Lũng Hầu đã vứt bỏ.","congNang":["Chỉ dẫn vị trí bí ẩn trong Trụy Ma Cốc"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0820","denChuong":"","cachCoDuoc":"Phát hiện giấu trong Thanh Tàm bào","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0820","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập phát hiện trong Thanh Tàm bào","text":"Hàn Lập xé góc Thanh Tàm bào lấy ra mảnh vải vẽ sơ đồ Trụy Ma Cốc có tiêu ký lớn. Ngân Nguyệt nhận ra đó là địa đồ.","anchor":"Đây là một khối địa đồ, hình như vẽ Trụy Ma Cốc"}]},"nguon":["@c0820"]},{"id":"kim-duong-chi","name":"Kim Dương chi","cn":"金阳芝","category":"nguyen-lieu","categoryLabel":"Linh thảo","phamCap":"Đỉnh giai","soHuu":["Hàn Lập","Nam Lũng Hầu","Lỗ Vệ Anh"],"trangThai":"đang sử dụng","blurb":"Linh thảo đỉnh giai Hỏa thuộc tính mọc bên hồ dung nham, là tài liệu luyện chế linh đan Hỏa thuộc tính.","detail":"Loại linh thảo đỉnh giai sinh tồn cạnh hồ dung nham trong nội cốc Trụy Ma Cốc. Là tài liệu đỉnh giai để luyện chế linh đan Hỏa thuộc tính. Ba người Hàn Lập, Nam Lũng Hầu, Lỗ Vệ Anh mỗi người hái mấy gốc.","congNang":["Tài liệu đỉnh giai luyện chế linh đan Hỏa thuộc tính"],"tabs":{"tienTrinh":[{"chuong":"@c0820","loai":"xuất hiện","importance":"normal","giaiDoan":"Ba người hái bên hồ dung nham","text":"Ba người Hàn Lập, Nam Lũng Hầu, Lỗ Vệ Anh hái linh thảo Kim Dương chi mọc bên hồ dung nham.","anchor":"là loại tài liệu đỉnh giai để luyện chế linh đan Hỏa thuộc tính"}]},"nguon":["@c0820"]},{"id":"thien-ly-ly","name":"Thiên Lý ly","cn":"千里離","category":"khac","categoryLabel":"Linh cầm","phamCap":"","soHuu":["Nam Lũng Hầu"],"trangThai":"đang sử dụng","blurb":"Chim nhỏ màu vàng kim được Nam Lũng Hầu thuần dưỡng, dùng trinh sát phạm vi vài chục dặm.","detail":"Linh cầm màu vàng kim do Nam Lũng Hầu thuần dưỡng, có khả năng tìm kiếm trinh sát trong phạm vi vài chục dặm. Được dùng để xác nhận Hàn Lập đã thực sự rời xa sau khi cáo từ.","congNang":["Tìm kiếm trinh sát tầm xa (vài chục dặm)"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0820","denChuong":"","cachCoDuoc":"Thuần dưỡng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0820","loai":"dùng","importance":"normal","giaiDoan":"Trinh sát xác nhận Hàn Lập đã rời đi","text":"Nam Lũng Hầu thả Thiên Lý ly tìm kiếm phạm vi vài chục dặm, xác nhận không có tung tích Hàn Lập.","anchor":"Đó chính là linh cầm “Thiên Lý ly” mà hắn thuần dưỡng"}]},"nguon":["@c0820"]},{"id":"phan-thuy-ky","name":"Phân Thủy Kỳ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Tiểu kỳ màu lam của Nam Lũng Hầu, có công năng rẽ nước, tách thủy mạc. Được dùng để cắm vào thủy đàm tạo vũng xoáy rồi mở thông đạo xuống đáy sâu ba trăm trượng.","detail":"Phân Thủy Kỳ là lá cờ nhỏ màu lam, pháp bảo hiếm có của Nam Lũng Hầu. Khi cắm vào thủy đàm, cờ tạo vũng xoáy rồi rẽ nước mở thông đạo, cho phép hai người bay xuống đáy đàm sâu khoảng ba trăm trượng. Lỗ Vệ Anh tỏ ra kinh ngạc khi thấy bảo vật này.","congNang":["Rẽ nước, tách thủy mạc, mở thông đạo dưới nước"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0821","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0821","loai":"dùng","importance":"normal","giaiDoan":"Rẽ nước thủy đàm","text":"Nam Lũng Hầu dùng Phân Thủy Kỳ cắm vào thủy đàm bích lục, tạo vũng xoáy rồi rẽ nước mở thông đạo xuống đáy sâu ba trăm trượng.","anchor":"Phân Thủy Kỳ? Không ngờ rằng Nam Lũng huynh còn có bảo vật hiếm có như vậy"}]},"nguon":["@c0821"]},{"id":"bo-khi-cu-bay-tran-thuy-thuoc-tinh","name":"Bộ khí cụ bày trận Thủy thuộc tính","category":"phap-bao","categoryLabel":"Khí cụ trận pháp","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Bộ khí cụ bày đại trận Thủy thuộc tính do Nam Lũng Hầu chuẩn bị sẵn để khắc chế Hỏa Thiềm thú.","detail":"Nam Lũng Hầu chuẩn bị sẵn từ trước chuyến đi, dùng bày đại trận Thủy thuộc tính ngoài sào huyệt Hỏa Thiềm thú, phối hợp với mấy pháp trận phụ của Hàn Lập trong kế dụ thú ra khỏi dung nham để diệt.","congNang":["Bày đại trận Thủy thuộc tính khắc chế yêu thú hệ Hỏa (@c0815)"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0815","denChuong":"","cachCoDuoc":"chuẩn bị sẵn từ trước chuyến đi","trangThai":"dang-co"}],"capNhatToi":"@c0815","tabs":{"tienTrinh":[{"chuong":"@c0815","loai":"xuất hiện","importance":"normal","text":"Nam Lũng Hầu lấy ra bày đại trận ngoài sào huyệt Hỏa Thiềm thú theo kế dụ thú.","anchor":"ta đã chuẩn bị một bộ khí cụ bày trận Thủy thuộc tính"}]},"nguon":["@c0815"]},{"id":"di-hai-tu-si-thuong-co","name":"Di hài tu sĩ thượng cổ","category":"khac","categoryLabel":"Di hài","trangThai":"chưa thu được","blurb":"Di hài của một tu sĩ thượng cổ nằm trong sào huyệt Hỏa Thiềm thú, mục tiêu chuyến đi của ba người.","detail":"Nằm trong động quật sào huyệt Hỏa Thiềm thú dưới chân núi lửa ở Dung Nham Chi Địa. Danh tính chủ nhân di hài chưa được hé lộ.","dacDiem":"Nằm trong sào huyệt Hỏa Thiềm thú, chưa rõ danh tính chủ nhân","capNhatToi":"@c0815","tabs":{"tienTrinh":[{"chuong":"@c0815","loai":"nhắc tới","importance":"normal","text":"Nam Lũng Hầu cho biết di hài nằm trong động quật sào huyệt Hỏa Thiềm thú dưới chân núi lửa.","anchor":"Di hài của tu sĩ thượng cổ cũng nằm ở trong đó"}]},"nguon":["@c0815"]},{"id":"khoi-loi-thu","name":"Khôi lỗi thú","trangThai":"mat","capNhatToi":"@c0815","tabs":{"tienTrinh":[{"chuong":"@c0815","loai":"hư tổn/tu bổ","importance":"normal","text":"Vài con cự viên tẩm Bích Cưu độc làm mồi dụ đàn Tử Vân hạt, va vào cấm chế bị đuổi kịp. Sau khi vượt núi, Hàn Lập cảm ứng chúng dần mất liên lạc, coi như tổn thất toàn bộ.","anchor":"Lúc này hắn cảm ứng được đám cự viên Khôi Lỗi dần dần mất liên lạc"}]},"nguon":["@c0815"]}]};
